        if node is None:
            return None
        clones = {}

        def dfs(n: "Node") -> "Node":
            if n in clones:
                return clones[n]
            clones[n] = Node(n.val)
            for nei in n.neighbors:
                clones[n].neighbors.append(dfs(nei))
            return clones[n]

        return dfs(node)

