class Solution {
    public java.util.List<java.util.List<Integer>> pacificAtlantic(int[][] heights) {
        int m = heights.length, n = heights[0].length;
        boolean[][] pac = new boolean[m][n], atl = new boolean[m][n];
        for (int i = 0; i < m; i++) { dfs(heights, pac, i, 0); dfs(heights, atl, i, n - 1); }
        for (int j = 0; j < n; j++) { dfs(heights, pac, 0, j); dfs(heights, atl, m - 1, j); }
        java.util.List<java.util.List<Integer>> res = new java.util.ArrayList<>();
        for (int i = 0; i < m; i++)
            for (int j = 0; j < n; j++)
                if (pac[i][j] && atl[i][j]) res.add(java.util.Arrays.asList(i, j));
        return res;
    }
    private void dfs(int[][] h, boolean[][] vis, int r, int c) {
        vis[r][c] = true;
        int[][] d = {{1,0},{-1,0},{0,1},{0,-1}};
        for (int[] t : d) {
            int nr = r + t[0], nc = c + t[1];
            if (nr < 0 || nc < 0 || nr >= h.length || nc >= h[0].length || vis[nr][nc] || h[nr][nc] < h[r][c]) continue;
            dfs(h, vis, nr, nc);
        }
    }
}

