class Solution:
    def ladderLength(self, beginWord: str, endWord: str, wordList: list[str]) -> int:
        words = set(wordList)
        if endWord not in words:
            return 0
        from collections import deque
        q = deque([beginWord])
        steps = 1
        while q:
            for _ in range(len(q)):
                w = q.popleft()
                if w == endWord:
                    return steps
                chars = list(w)
                for i in range(len(chars)):
                    old = chars[i]
                    for c in "abcdefghijklmnopqrstuvwxyz":
                        chars[i] = c
                        nxt = "".join(chars)
                        if nxt in words:
                            words.remove(nxt)
                            q.append(nxt)
                    chars[i] = old
            steps += 1
        return 0

