        for _ in range(k + 1):
            nxt = dist[:]
            for u, v, w in flights:
                if dist[u] != float("inf") and dist[u] + w < nxt[v]:
                    nxt[v] = dist[u] + w
            dist = nxt
        return -1 if dist[dst] == float("inf") else dist[dst]

