class Solution {
    private int timer = 0;
    public java.util.List<java.util.List<Integer>> criticalConnections(int n, java.util.List<java.util.List<Integer>> connections) {
        java.util.List<java.util.List<Integer>> g = new java.util.ArrayList<>();
        for (int i = 0; i < n; i++) g.add(new java.util.ArrayList<>());
        for (java.util.List<Integer> e : connections) {
            g.get(e.get(0)).add(e.get(1));
            g.get(e.get(1)).add(e.get(0));
        }
        int[] disc = new int[n], low = new int[n];
        java.util.Arrays.fill(disc, -1);
        java.util.List<java.util.List<Integer>> bridges = new java.util.ArrayList<>();
        dfs(0, -1, g, disc, low, bridges);
        return bridges;
    }
    private void dfs(int u, int parent, java.util.List<java.util.List<Integer>> g, int[] disc, int[] low, java.util.List<java.util.List<Integer>> bridges) {
        disc[u] = low[u] = timer++;
        for (int v : g.get(u)) {
            if (v == parent) continue;
            if (disc[v] == -1) {
                dfs(v, u, g, disc, low, bridges);
                low[u] = Math.min(low[u], low[v]);
                if (low[v] > disc[u]) bridges.add(java.util.Arrays.asList(u, v));
            } else low[u] = Math.min(low[u], disc[v]);
        }
    }
}

